// Allowlist of permitted redirect domains
const ALLOWED_ORIGINS = [
  'https://myapp.com',
  'https://www.myapp.com',
  'https://app.myapp.com',
  'https://staging.myapp.com'
];

// Default safe redirect if validation fails
const DEFAULT_REDIRECT = '/dashboard';

/**
 * Validates that a return URL is safe to redirect to.
 * Only allows:
 *   - Relative paths (starting with / but not //)
 *   - Absolute URLs whose origin is in the allowlist
 */
function isValidReturnUrl(returnUrl) {
  if (!returnUrl || typeof returnUrl !== 'string') {
    return false;
  }

  // Trim whitespace to prevent bypass with leading spaces
  const trimmed = returnUrl.trim();

  // Block protocol-relative URLs (e.g., //evil.com)
  if (trimmed.startsWith('//')) {
    return false;
  }

  // Block URLs with dangerous schemes (javascript:, data:, vbscript:, etc.)
  const lowerTrimmed = trimmed.toLowerCase().replace(/\s/g, '');
  if (/^[a-z]+:/i.test(lowerTrimmed) && !lowerTrimmed.startsWith('https://') && !lowerTrimmed.startsWith('http://')) {
    return false;
  }

  // Allow relative paths that start with a single /
  if (trimmed.startsWith('/') && !trimmed.startsWith('//')) {
    // Additional check: ensure no backslash tricks (e.g., /\evil.com)
    if (trimmed.includes('\\')) {
      return false;
    }
    return true;
  }

  // For absolute URLs, validate against the allowlist of origins
  try {
    const parsed = new URL(trimmed);
    const origin = parsed.origin;
    return ALLOWED_ORIGINS.includes(origin);
  } catch (e) {
    // If URL parsing fails, it's not a valid URL — reject it
    return false;
  }
}

